import axios from 'axios';

const backendURL = 'http://localhost:3000/api/levels';

// Get authorization header
const getAuthHeader = () => {
    const token = localStorage.getItem('token');
    return token ? { Authorization: token } : {};
};

// Get all levels
export const getAllLevels = async () => {
    try {
        const response = await axios.get(backendURL);
        return response.data;
    } catch (error) {
        console.error('Get all levels error:', error);
        throw error;
    }
};

// Create a new level
export const createLevel = async (levelData) => {
    try {
        const response = await axios.post(backendURL, levelData, {
            headers: getAuthHeader()
        });
        return response.data;
    } catch (error) {
        console.error('Create level error:', error);
        throw error;
    }
};

// Get level by ID
export const getLevel = async (id) => {
    try {
        const response = await axios.get(`${backendURL}/${id}`);
        return response.data;
    } catch (error) {
        console.error('Get level error:', error);
        throw error;
    }
};

// Update level
export const updateLevel = async (id, levelData) => {
    try {
        const response = await axios.put(`${backendURL}/${id}`, levelData, {
            headers: getAuthHeader()
        });
        return response.data;
    } catch (error) {
        console.error('Update level error:', error);
        throw error;
    }
};

// Delete level
export const deleteLevel = async (id) => {
    try {
        const response = await axios.delete(`${backendURL}/${id}`, {
            headers: getAuthHeader()
        });
        return response.data;
    } catch (error) {
        console.error('Delete level error:', error);
        throw error;
    }
};

// Get level by number
export const getLevelByNumber = async (number) => {
    try {
        const response = await axios.get(`${backendURL}/number/${number}`);
        return response.data;
    } catch (error) {
        console.error('Get level by number error:', error);
        throw error;
    }
};

// Get boss levels
export const getBossLevels = async () => {
    try {
        const response = await axios.get(`${backendURL}/boss`);
        return response.data;
    } catch (error) {
        console.error('Get boss levels error:', error);
        throw error;
    }
};
